// Calcola collected_period da collected_at + cadenza
function getCollectedPeriod(collectedAt, cadenza) {
  const d = new Date(collectedAt || new Date().toISOString());
  const pad = (n) => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  // ISO week number
  const startOfYear = new Date(Date.UTC(yyyy, 0, 1));
  const weekNo = pad(Math.ceil(((d - startOfYear) / 86400000 + startOfYear.getUTCDay() + 1) / 7));
  switch((cadenza || '').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${weekNo}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}

const _cadenza = 'daily';
const _collectedAt = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(_collectedAt, _cadenza);
const snapshot = $json;
const collectedAt = snapshot.completed_at || new Date().toISOString();
const ports = Array.isArray(snapshot.ports) ? snapshot.ports : [];

function slug(value) {
  return String(value ?? '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

const congestedPorts = ports.filter((port) => Number(port.anchored_vessels_count ?? 0) > 0);
const totalAnchored = Number(snapshot.total_anchored_vessels ?? 0);
const topPort = snapshot.top_congested_port && Number(snapshot.top_congested_port.anchored_vessels_count ?? 0) > 0
  ? snapshot.top_congested_port
  : (congestedPorts[0] ?? null);

const signals = [];
if (totalAnchored === 0) signals.push('no_port_queue_detected');
if (totalAnchored > 0) signals.push('port_queue_detected');
if (congestedPorts.length >= 2) signals.push('multi_port_congestion');
if (congestedPorts.length >= 3) signals.push('widespread_port_congestion');
if (topPort && Number(topPort.anchored_vessels_count ?? 0) >= 3) signals.push('moderate_queue_' + slug(topPort.port_name));
if (topPort && Number(topPort.anchored_vessels_count ?? 0) >= 6) signals.push('high_queue_' + slug(topPort.port_name));
if (totalAnchored >= 8) signals.push('regional_export_delay_risk');
if (Array.isArray(snapshot.errors) && snapshot.errors.length) signals.push('snapshot_data_quality_watch');


const perPortText = ports
  .map((port) => port.port_name + ': ' + Number(port.anchored_vessels_count ?? 0) + ' anchored vessels')
  .join('; ');

let summaryEn;
if (!congestedPorts.length) {
  summaryEn = 'No anchored vessel accumulation was detected across the monitored Brazilian port anchorage zones during the ' + snapshot.snapshot_seconds + '-second AIS snapshot.';
} else {
  summaryEn = totalAnchored + ' anchored or near-stationary vessels were detected across ' + congestedPorts.length + ' monitored Brazilian port zones during the ' + snapshot.snapshot_seconds + '-second AIS snapshot.';
  if (topPort) {
    summaryEn += ' The most congested area was ' + topPort.port_name + ' with ' + topPort.anchored_vessels_count + ' vessels in queue-like conditions.';
  }
}

const embedText = [
  summaryEn,
  perPortText,
  ...signals,
].filter(Boolean).join(' ');

return [{
  json: {
    source: 'AISSTREAM_PORT_CONGESTION',
    source_url: 'wss://stream.aisstream.io/v0/stream',
    source_format: 'websocket_snapshot',
    country: 'BR',
    macroarea: 'geo',
    collected_at: collectedAt,
    started_at: snapshot.started_at || null,
    status: snapshot.status || 'done',
    snapshot_seconds: Number(snapshot.snapshot_seconds ?? 0),
    ports_monitored: Number(snapshot.ports_monitored ?? ports.length),
    port_names: Array.isArray(snapshot.port_names) ? snapshot.port_names : ports.map((port) => port.port_name),
    raw_messages_received: Number(snapshot.raw_messages_received ?? 0),
    position_reports_received: Number(snapshot.position_reports_received ?? 0),
    port_reports_received: Number(snapshot.port_reports_received ?? 0),
    total_anchored_vessels: totalAnchored,
    congested_ports_count: congestedPorts.length,
    top_congested_port: topPort ? {
      port_name: topPort.port_name,
      anchored_vessels_count: Number(topPort.anchored_vessels_count ?? 0),
      average_sog: Number(topPort.average_sog ?? 0),
    } : null,
signals: Array.from(new Set(signals)),
    summary_en: summaryEn,
    embed_text: embedText,
    ports,
    errors: Array.isArray(snapshot.errors) ? snapshot.errors : [],
  }
}];

// Calcola collected_period da collected_at + cadenza
function getCollectedPeriod(collectedAt, cadenza) {
  const d = new Date(collectedAt || new Date().toISOString());
  const pad = (n) => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
