const _cadenza = 'daily';
const _collectedAt = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(_collectedAt, _cadenza);
const meta = $('Port Congestion Parse').item.json;
const vector = $json.data[0].embedding;
const key = meta.source + '|' + meta.collected_at + '|' + meta.total_anchored_vessels + '|' + meta.port_reports_received;
let hash = 0;
for (let i = 0; i < key.length; i++) {
  hash = ((hash << 5) - hash) + key.charCodeAt(i);
  hash |= 0;
}
const pointId = Math.abs(hash);

return [{
  json: {
    points: [{
      id: pointId,
      vector,
      payload: {
        source: meta.source,
        country: meta.country,
        macroarea: meta.macroarea,
        collected_at: meta.collected_at,
        snapshot_seconds: meta.snapshot_seconds,
        total_anchored_vessels: meta.total_anchored_vessels,
        congested_ports_count: meta.congested_ports_count,
        top_congested_port: meta.top_congested_port ? meta.top_congested_port.port_name : null,
summary_en: meta.summary_en,
        signals: meta.signals,
        port_names: meta.port_names,
      },
    }],
  },
}];

const now = new Date().toISOString();
const meta = $('Port Congestion Parse').item.json;

return [{
  json: {
    source: 'AISSTREAM_PORT_CONGESTION',
    country: 'BR',
    macroarea: 'geo',
    cadenza: 'hourly',
    run_date: now,
    status: 'done',
    completed_at: now,
    items_ingested: meta.total_anchored_vessels,
  },
}];

const item = $input.first();
const err = item.json?.error ?? item.error?.message ?? '';
const statusCode = item.json?.statusCode ?? item.json?.status ?? 0;
if (err || statusCode >= 400) {
  return [{ json: {
    _api_skip: true,
    source: '02_PORT_CONGESTION',
    country: 'BR',
    status: 'skipped_api_error',
    reason: `API unavailable: ${err || 'HTTP ' + statusCode}`,
    run_date: new Date().toISOString(),
    completed_at: new Date().toISOString()
  } }];
}
return [{ json: item.json }];
